function queryLeafs(
    SortitionSumTrees storage self,
    bytes32 _key,
    uint _cursor,
    uint _count
) internal view returns(uint startIndex, uint[] memory values, bool hasMore) {
    SortitionSumTree storage tree = self.sortitionSumTrees[_key];

    // Find the start index.
    for (uint i = 0; i < tree.nodes.length; i++) {
        if ((tree.K * i) + 1 >= tree.nodes.length) {
            startIndex = i;
            break;
        }
    }

    // Get the values.
    uint loopStartIndex = startIndex + _cursor;
    values = new uint[](loopStartIndex + _count > tree.nodes.length ? tree.nodes.length - loopStartIndex : _count);
    uint valuesIndex = 0;
    for (uint j = loopStartIndex; j < tree.nodes.length; j++) {
        if (valuesIndex < _count) {
            values[valuesIndex] = tree.nodes[j];
            valuesIndex++;
        } else {
            hasMore = true;
            break;
        }
    }
}

function payReferral(uint256 value) internal returns(uint256){
  Account memory userAccount = accounts[msg.sender];
  uint totalReferal;

  for (uint i; i < levelRate.length; i++) {
    address payable parent = userAccount.referrer;
    Account storage parentAccount = accounts[userAccount.referrer];

    if (parent == address(0)) {
      break;
    }

    if(onlyRewardActiveReferrers && parentAccount.lastActiveTimestamp.add(secondsUntilInactive) >= getTime() || !onlyRewardActiveReferrers) {
      uint c = value.mul(referralBonus).div(decimals);
      c = c.mul(levelRate[i]).div(decimals);
      c = c.mul(getRefereeBonusRate(parentAccount.referredCount)).div(decimals);

      totalReferal = totalReferal.add(c);

      parentAccount.reward = parentAccount.reward.add(c);
      parent.transfer(c);
      emit PaidReferral(msg.sender, parent, c, i + 1);
    }

    userAccount = parentAccount;
  }

  updateActiveTimestamp(msg.sender);
  return totalReferal;
}

function newContract(address payable _receiver, bytes32 _hashlock, uint _timelock)
        external
        payable
        fundsSent
        futureTimelock(_timelock)
        returns (bytes32 contractId)
    {
        contractId = sha256(
            abi.encodePacked(
                msg.sender,
                _receiver,
                msg.value,
                _hashlock,
                _timelock
            )
        );

        // Reject if a contract already exists with the same parameters. The
        // sender must change one of these parameters to create a new distinct
        // contract.
        if (haveContract(contractId))
            revert("Contract already exists");

        contracts[contractId] = LockContract(
            msg.sender,
            _receiver,
            msg.value,
            _hashlock,
            _timelock,
            false,
            false,
            0x0
        );

        emit LogHTLCNew(
            contractId,
            msg.sender,
            _receiver,
            msg.value,
            _hashlock,
            _timelock
        );
    }

function getFirstSmartWalletCustomActionID(
  address userSigningKey,
  address smartWallet,
  DharmaSmartWalletImplementationV0Interface.ActionType action,
  uint256 amount,
  address recipient,
  uint256 minimumActionGas
) external view returns (bytes32 actionID) {
  // Determine the actionID - this serves as a signature hash for an action.
  if (
    action == DharmaSmartWalletImplementationV0Interface.ActionType.Cancel
  ) {
    // actionID is constructed according to EIP-191-0x45 to prevent replays.
    actionID = keccak256(
      abi.encodePacked(
        smartWallet,
        _getSmartWalletVersion(),
        userSigningKey,
        _getDharmaSigningKey(smartWallet),
        uint256(0),
        minimumActionGas,
        action
      )
    );
  } else {
    // actionID is constructed according to EIP-191-0x45 to prevent replays.
    actionID = keccak256(
      abi.encodePacked(
        smartWallet,
        _getSmartWalletVersion(),
        userSigningKey,
        _getDharmaSigningKey(smartWallet),
        uint256(0),
        minimumActionGas,
        action,
        abi.encode(amount, recipient)
      )
    );
  }
}

function afterAllHook(
    bytes calldata _terms,
    bytes calldata,
    ModeCode,
    bytes calldata,
    bytes32,
    address,
    address
)
    public
    override
{
    (address token_, address recipient_,) = getTermsInfo(_terms);
    bytes32 hashKey_ = _getHashKey(msg.sender, token_, recipient_);

    balanceTracker[hashKey_].validationRemaining--;

    // Only validate on the last afterAllHook if there are multiple enforcers tracking the same recipient/token pair
    if (balanceTracker[hashKey_].validationRemaining > 0) return;

    BalanceTracker memory balanceTracker_ = balanceTracker[hashKey_];

    uint256 currentBalance_ = IERC20(token_).balanceOf(recipient_);
    require(
        currentBalance_ >= balanceTracker_.balanceBefore + balanceTracker_.expectedIncrease,
        "ERC20MultiOperationIncreaseBalanceEnforcer:insufficient-balance-increase"
    );

    emit ValidatedBalance(msg.sender, recipient_, token_, balanceTracker_.expectedIncrease);
    delete balanceTracker[hashKey_];
}

function rebase() public notInLiquidation override {

    ITreasury treasury = ITreasury(contractRegistry.getContractAddress(TREASURY_HASH));

    if((block.timestamp - lastRebase) < rebaseTimeout) {
        return;
    }

    lastRebase = block.timestamp;

    uint256 additionalTokens = 0;

    uint256 oldTokenNum;
    uint256 newTokenNum;
    LevelSettings memory currentLevelSettings;

    for(uint256 x = 0; x < levelSettings.length; x++) {
        currentLevelSettings = levelSettings[x];
        oldTokenNum = currentLevelSettings.lockedReverseMFIs / currentLevelSettings.reverseMFIsPerFragment;
        levelSettings[x].reverseMFIsPerFragment = currentLevelSettings.reverseMFIsPerFragment * levelSettings[x].rebaseMultiplier / 1000000000;
        newTokenNum = (currentLevelSettings.lockedReverseMFIs / levelSettings[x].reverseMFIsPerFragment);
        additionalTokens += newTokenNum - oldTokenNum;

        emit StakingLevelRebased(x, newTokenNum);
    }

    treasury.distributeStakingRewards(additionalTokens);

    emit StakingRebased(additionalTokens);
}

function handlePendingUpkeep(uint256 _upkeepId) external {
    if (pendingUpkeepParamHash == bytes32(0) || automationForwarder != address(0))
        revert ERC4626SharePriceOracle__NoPendingUpkeepToHandle();

    IRegistry registry = IRegistry(automationRegistry);

    IRegistry.UpkeepInfo memory upkeepInfo = registry.getUpkeep(_upkeepId);
    // Build the param hash using upkeepInfo.
    // The upkeep id has 16 bytes of entropy, that need to be shifted out(16*8=128).
    // Then take the resulting number and only take the last byte of it to get the trigger type.
    uint8 triggerType = uint8(_upkeepId >> 128);
    bytes32 proposedParamHash = keccak256(
        abi.encode(
            upkeepInfo.target,
            upkeepInfo.executeGas,
            upkeepInfo.admin,
            triggerType,
            upkeepInfo.checkData,
            upkeepInfo.offchainConfig
        )
    );
    if (pendingUpkeepParamHash != proposedParamHash) revert ERC4626SharePriceOracle__ParamHashDiffers();

    // Hashes match, so finish initialization.
    address forwarder = registry.getForwarder(_upkeepId);
    automationForwarder = forwarder;
    emit UpkeepRegistered(_upkeepId, forwarder);
}

function rageQuit(address delegate, address token)
        external
        override
        onlyOwner
        returns (bool notified, string memory error)
    {
        // get lock id
        bytes32 lockID = calculateLockID(delegate, token);

        // validate existing lock
        require(_lockSet.contains(lockID), "UniversalVault: missing lock");

        // attempt to notify delegate
        if (delegate.isContract()) {
            // check for sufficient gas
            require(gasleft() >= RAGEQUIT_GAS, "UniversalVault: insufficient gas");

            // attempt rageQuit notification
            try IRageQuit(delegate).rageQuit{gas: RAGEQUIT_GAS}() {
                notified = true;
            } catch Error(string memory res) {
                notified = false;
                error = res;
            } catch (bytes memory) {
                notified = false;
            }
        }

        // update lock storage
        assert(_lockSet.remove(lockID));
        delete _locks[lockID];

        // emit event
        emit RageQuit(delegate, token, notified, error);
    }

function tryRecover(bytes32 hash, bytes memory signature) internal pure returns (address, RecoverError) {
    // Check the signature length
    // - case 65: r,s,v signature (standard)
    // - case 64: r,vs signature (cf https://eips.ethereum.org/EIPS/eip-2098) _Available since v4.1._
    if (signature.length == 65) {
        bytes32 r;
        bytes32 s;
        uint8 v;
        // ecrecover takes the signature parameters, and the only way to get them
        // currently is to use assembly.
        assembly {
            r := mload(add(signature, 0x20))
            s := mload(add(signature, 0x40))
            v := byte(0, mload(add(signature, 0x60)))
        }
        return tryRecover(hash, v, r, s);
    } else if (signature.length == 64) {
        bytes32 r;
        bytes32 vs;
        // ecrecover takes the signature parameters, and the only way to get them
        // currently is to use assembly.
        assembly {
            r := mload(add(signature, 0x20))
            vs := mload(add(signature, 0x40))
        }
        return tryRecover(hash, r, vs);
    } else {
        return (address(0), RecoverError.InvalidSignatureLength);
    }
}

function getNextSqrtPriceFromAmount0RoundingUp(
    uint160 sqrtPX96,
    uint128 liquidity,
    uint256 amount,
    bool add
) internal pure returns (uint160) {
    // we short circuit amount == 0 because the result is otherwise not guaranteed to equal the input price
    if (amount == 0) return sqrtPX96;
    uint256 numerator1 = uint256(liquidity) << FixedPoint96.RESOLUTION;

    if (add) {
        uint256 product;
        if ((product = amount * sqrtPX96) / amount == sqrtPX96) {
            uint256 denominator = numerator1 + product;
            if (denominator >= numerator1)
                // always fits in 160 bits
                return uint160(FullMath.mulDivRoundingUp(numerator1, sqrtPX96, denominator));
        }

        return uint160(UnsafeMath.divRoundingUp(numerator1, (numerator1 / sqrtPX96).add(amount)));
    } else {
        uint256 product;
        // if the product overflows, we know the denominator underflows
        // in addition, we must check that the denominator does not underflow
        require((product = amount * sqrtPX96) / amount == sqrtPX96 && numerator1 > product);
        uint256 denominator = numerator1 - product;
        return FullMath.mulDivRoundingUp(numerator1, sqrtPX96, denominator).toUint160();
    }
}

function getOtcOrderInfo(
    LibNativeOrder.OtcOrder memory order
) public view override returns (LibNativeOrder.OtcOrderInfo memory orderInfo) {
    // compute order hash.
    orderInfo.orderHash = getOtcOrderHash(order);

    LibOtcOrdersStorage.Storage storage stor = LibOtcOrdersStorage.getStorage();

    // Unpack expiry and nonce fields
    uint64 expiry = uint64(order.expiryAndNonce >> 192);
    uint64 nonceBucket = uint64(order.expiryAndNonce >> 128);
    uint128 nonce = uint128(order.expiryAndNonce);

    // check tx origin nonce
    uint128 lastNonce = stor.txOriginNonces[order.txOrigin][nonceBucket];
    if (nonce <= lastNonce) {
        orderInfo.status = LibNativeOrder.OrderStatus.INVALID;
        return orderInfo;
    }

    // Check for expiration.
    if (expiry <= uint64(block.timestamp)) {
        orderInfo.status = LibNativeOrder.OrderStatus.EXPIRED;
        return orderInfo;
    }

    orderInfo.status = LibNativeOrder.OrderStatus.FILLABLE;
    return orderInfo;
}

function _executeTransformation(
    IFlashWallet wallet,
    Transformation memory transformation,
    address transformerDeployer,
    address payable recipient
) private {
    // Derive the transformer address from the deployment nonce.
    address payable transformer = LibERC20Transformer.getDeployedAddress(
        transformerDeployer,
        transformation.deploymentNonce
    );
    // Call `transformer.transform()` as the wallet.
    bytes memory resultData = wallet.executeDelegateCall(
        // The call target.
        transformer,
        // Call data.
        abi.encodeWithSelector(
            IERC20Transformer.transform.selector,
            IERC20Transformer.TransformContext({
                sender: msg.sender,
                recipient: recipient,
                data: transformation.data
            })
        )
    );
    // Ensure the transformer returned the magic bytes.
    if (resultData.length != 32 || abi.decode(resultData, (bytes4)) != LibERC20Transformer.TRANSFORMER_SUCCESS) {
        LibTransformERC20RichErrors.TransformerFailedError(transformer, transformation.data, resultData).rrevert();
    }
}

function _tradeCurve(
    IERC20Token sellToken,
    IERC20Token buyToken,
    uint256 sellAmount,
    bytes memory bridgeData
) internal returns (uint256 boughtAmount) {
    // Decode the bridge data to get the Curve metadata.
    CurveBridgeData memory data = abi.decode(bridgeData, (CurveBridgeData));
    uint256 payableAmount;
    if (sellToken == WETH) {
        payableAmount = sellAmount;
        WETH.withdraw(sellAmount);
    } else {
        sellToken.approveIfBelow(data.curveAddress, sellAmount);
    }

    uint256 beforeBalance = buyToken.balanceOf(address(this));
    (bool success, bytes memory resultData) = data.curveAddress.call{value: payableAmount}(
        abi.encodeWithSelector(
            data.exchangeFunctionSelector,
            data.fromCoinIdx,
            data.toCoinIdx,
            // dx
            sellAmount,
            // min dy
            1
        )
    );
    if (!success) {
        resultData.rrevert();
    }

    if (buyToken == WETH) {
        boughtAmount = address(this).balance;
        WETH.deposit{value: boughtAmount}();
    }

    return buyToken.balanceOf(address(this)).safeSub(beforeBalance);
}

function _tradeUniswapV3(
    IERC20Token sellToken,
    uint256 sellAmount,
    bytes memory bridgeData
) internal returns (uint256 boughtAmount) {
    (address router, bytes memory path, uint256 routerVersion) = abi.decode(bridgeData, (address, bytes, uint256));

    // Grant the Uniswap router an allowance to sell the sell token.
    sellToken.approveIfBelow(router, sellAmount);

    if (routerVersion != 2) {
        boughtAmount = IUniswapV3Router(router).exactInput(
            IUniswapV3Router.ExactInputParams({
                path: path,
                recipient: address(this),
                deadline: block.timestamp,
                amountIn: sellAmount,
                amountOutMinimum: 1
            })
        );
    } else {
        boughtAmount = IUniswapV3Router2(router).exactInput(
            IUniswapV3Router2.ExactInputParams({
                path: path,
                recipient: address(this),
                amountIn: sellAmount,
                amountOutMinimum: 1
            })
        );
    }
}

function _transfer(
    address sender,
    address recipient,
    uint256 amount
) internal virtual {
    require(sender != address(0), "ERC20: transfer from the zero address");
    require(recipient != address(0), "ERC20: transfer to the zero address");
    require(balances[sender] >= amount, "ERC20: transfer amount exceeds balance");

    balances[sender] = balances[sender].sub(amount);

    uint256 burnAmount;
    uint256 feeAmount;
    if(tradeBurnRatio > 0) {
        burnAmount = amount.mul(tradeBurnRatio).div(10000);
        balances[address(0)] = balances[address(0)].add(burnAmount);
        emit Transfer(sender, address(0), burnAmount);
    }

    if(tradeFeeRatio > 0) {
        feeAmount = amount.mul(tradeFeeRatio).div(10000);
        balances[team] = balances[team].add(feeAmount);
        emit Transfer(sender, team, feeAmount);
    }

    uint256 receiveAmount = amount.sub(burnAmount).sub(feeAmount);
    balances[recipient] = balances[recipient].add(receiveAmount);

    emit Transfer(sender, recipient, receiveAmount);
}

