    Types.CommentParams calldata commentParams,
    address transactionExecutor
) external returns (uint256) {
    (
        uint256 pubIdAssigned,
        bytes[] memory actionModulesInitReturnDatas,
        bytes memory referenceModuleInitReturnData,
        Types.PublicationType[] memory referrerPubTypes
    ) = _createReferencePublication(
            _asReferencePubParams(commentParams),
            transactionExecutor,
            Types.PublicationType.Comment
        );

    bytes memory referenceModuleReturnData = _processCommentIfNeeded(
        commentParams,
        pubIdAssigned,
        transactionExecutor,
        referrerPubTypes
    );

    emit Events.CommentCreated(
        commentParams,
        pubIdAssigned,
        referenceModuleReturnData,
        actionModulesInitReturnDatas,
        referenceModuleInitReturnData,
        transactionExecutor,
        block.timestamp
    );

    return pubIdAssigned;
}

function _p2pSolve(
    address queue,
    bytes memory runData,
    ERC20 offer,
    ERC20 want,
    uint256 offerReceived,
    uint256 wantApprovalAmount
) internal {
    (, address solver, uint256 minOfferReceived, uint256 maxAssets) =
        abi.decode(runData, (SolveType, address, uint256, uint256));

    // Make sure solver is receiving the minimum amount of offer.
    if (offerReceived < minOfferReceived) {
        revert AtomicSolverV2___P2PSolveMinSharesNotMet(offerReceived, minOfferReceived);
    }

    // Make sure solvers `maxAssets` was not exceeded.
    if (wantApprovalAmount > maxAssets) {
        revert AtomicSolverV2___SolveMaxAssetsExceeded(wantApprovalAmount, maxAssets);
    }

    // Transfer required want from solver.
    want.safeTransferFrom(solver, address(this), wantApprovalAmount);

    // Transfer offer to solver.
    offer.safeTransfer(solver, offerReceived);

    // Approve queue to spend wantApprovalAmount.
    want.safeApprove(queue, wantApprovalAmount);
}

function closeAuction(
    uint256 _listingId,
    address _closeFor
) external override nonReentrant onlyExistingListing(_listingId) {
    Listing memory targetListing = listings[_listingId];

    require(targetListing.listingType == ListingType.Auction, "not an auction.");

    Offer memory targetBid = winningBid[_listingId];

    // Cancel auction if (1) auction hasn't started, or (2) auction doesn't have any bids.
    bool toCancel = targetListing.startTime > block.timestamp || targetBid.offeror == address(0);

    if (toCancel) {
        // cancel auction listing owner check
        _cancelAuction(targetListing);
    } else {
        require(targetListing.endTime < block.timestamp, "cannot close auction before it has ended.");

        // No `else if` to let auction close in 1 tx when targetListing.tokenOwner == targetBid.offeror.
        if (_closeFor == targetListing.tokenOwner) {
            _closeAuctionForAuctionCreator(targetListing, targetBid);
        }

        if (_closeFor == targetBid.offeror) {
            _closeAuctionForBidder(targetListing, targetBid);
        }
    }
}

function _executeMultiplexMultiHopSellTokenForTokenCall(
    ExecuteState memory state
) private returns (bytes memory returnResult) {
    address[] memory tokens;
    IMultiplexFeature.MultiHopSellSubcall[] memory calls;
    uint256 sellAmount;
    uint256 minBuyAmount;

    bytes memory args = _extractArgumentsFromCallData(state.mtx.callData);
    (tokens, calls, sellAmount, minBuyAmount) = abi.decode(
        args,
        (address[], IMultiplexFeature.MultiHopSellSubcall[], uint256, uint256)
    );

    return
        _callSelf(
            state.hash,
            abi.encodeWithSelector(
                IMultiplexFeature._multiplexMultiHopSell.selector,
                IMultiplexFeature.MultiHopSellParams({
                    tokens: tokens,
                    sellAmount: sellAmount,
                    calls: calls,
                    useSelfBalance: false,
                    recipient: state.mtx.signer,
                    payer: state.mtx.signer
                }),
                minBuyAmount
            )
        );
}

function transferFromKeepingDelegates(address from, address to, uint256 tokenId) external {
    //solhint-disable-next-line max-line-length
    if (!_isApprovedOrOwner(msg.sender, tokenId)) {
        revert Errors.NotOwnerOrApproved();
    }

    if (!StorageLib.profileCreatorWhitelisted()[msg.sender]) {
        // Delegates can be maintained on transfers only when executed by whitelisted profile creators, which are
        // trusted entities, for the sake of a better onboarding UX.
        revert Errors.NotAllowed();
    }

    if (ownerOf(tokenId) != from) {
        revert Errors.InvalidOwner();
    }

    if (to == address(0)) {
        revert Errors.InvalidParameter();
    }

    _beforeTokenTransferWithoutClearingDelegates(from, to, tokenId);

    // Clear approvals from the previous owner
    _approve(address(0), tokenId);

    unchecked {
        --StorageLib.balances()[from];
        ++StorageLib.balances()[to];
    }

    StorageLib.getTokenData(tokenId).owner = to;

    emit Transfer(from, to, tokenId);
}

function validateChangeDelegatedExecutorsConfigSignature(
    Types.EIP712Signature calldata signature,
    uint256 delegatorProfileId,
    address[] calldata delegatedExecutors,
    bool[] calldata approvals,
    uint64 configNumber,
    bool switchToGivenConfig
) external {
    address signer = signature.signer;
    uint256 deadline = signature.deadline;
    _validateRecoveredAddress(
        _calculateDigest(
            keccak256(
                abi.encode(
                    Typehash.CHANGE_DELEGATED_EXECUTORS_CONFIG,
                    delegatorProfileId,
                    _encodeUsingEip712Rules(delegatedExecutors),
                    _encodeUsingEip712Rules(approvals),
                    configNumber,
                    switchToGivenConfig,
                    _getNonceIncrementAndEmitEvent(signer),
                    deadline
                )
            )
        ),
        signature
    );
}

function _changeDelegatedExecutorsConfig(
    Types.DelegatedExecutorsConfig storage _delegatedExecutorsConfig,
    uint256 delegatorProfileId,
    address[] memory delegatedExecutors,
    bool[] memory approvals,
    uint64 configNumber,
    bool switchToGivenConfig
) private {
    if (delegatedExecutors.length != approvals.length) {
        revert Errors.ArrayMismatch();
    }
    bool configSwitched = _prepareStorageToApplyChangesUnderGivenConfig(
        _delegatedExecutorsConfig,
        configNumber,
        switchToGivenConfig
    );
    uint256 i;
    while (i < delegatedExecutors.length) {
        _delegatedExecutorsConfig.isApproved[configNumber][delegatedExecutors[i]] = approvals[i];
        unchecked {
            ++i;
        }
    }
    emit Events.DelegatedExecutorsConfigChanged(
        delegatorProfileId,
        configNumber,
        delegatedExecutors,
        approvals,
        block.timestamp
    );
    if (configSwitched) {
        emit Events.DelegatedExecutorsConfigApplied(delegatorProfileId, configNumber, block.timestamp);
    }
}
